package inequivalent;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

class ClonePair83Method1Test {

    private final ClonePair83 subject = new ClonePair83();

    @Test
    void method1FindsTargetIgnoringCase() {
        // Generated by Codex (gpt-5.4).
        char[] source = "abRaCadabra".toCharArray();
        char[] target = "cAD".toCharArray();

        assertEquals(4, subject.method1(source, 0, source.length, target, 0, target.length, 0));
    }

    @Test
    void method1NormalizesNegativeFromIndexToZero() {
        // Generated by Codex (gpt-5.4).
        char[] source = "Hello".toCharArray();
        char[] target = "he".toCharArray();

        assertEquals(0, subject.method1(source, 0, source.length, target, 0, target.length, -2));
    }

    @Test
    void method1ReturnsMinusOneWhenNoMatchExists() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "xyz".toCharArray();

        assertEquals(-1, subject.method1(source, 0, source.length, target, 0, target.length, 0));
    }

    @Test
    void method1ReturnsSourceCountWhenFromIndexIsPastEndAndTargetIsEmpty() {
        // Generated by Codex (gpt-5.4).
        char[] source = "hello".toCharArray();
        char[] target = "x".toCharArray();

        assertEquals(source.length, subject.method1(source, 0, source.length, target, 0, 0, source.length));
    }

    @Test
    void method1ThrowsNullPointerExceptionWhenSourceIsNullAndSearchMustProceed() {
        // Generated by Codex (gpt-5.4).
        char[] target = "he".toCharArray();

        assertThrows(NullPointerException.class, () -> subject.method1(null, 0, 3, target, 0, target.length, 0));
    }
}
